/* ============================================================
   BEACON ATLAS - 3D Holographic City Map
   CRT Terminal Aesthetic
   ============================================================ */

:root {
  --green: #33ff33;
  --green-dim: #1a8c1a;
  --green-glow: #00ff0044;
  --amber: #ffb000;
  --amber-dim: #996a00;
  --red: #ff4444;
  --cyan: #00ffff;
  --gold: #ffd700;
  --pink: #ff88cc;
  --purple: #8888ff;
  --magenta: #ff44ff;
  --bg-dark: #0a0a0a;
  --bg-terminal: #000800;
  --bg-panel: rgba(0, 8, 0, 0.92);
  --border: #1a331a;
  --text-dim: #668866;
  --text-body: #a0c8a0;
  --font-mono: 'IBM Plex Mono', 'Share Tech Mono', 'Courier New', monospace;
  --font-display: 'VT323', 'IBM Plex Mono', monospace;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
  width: 100%; height: 100%;
  overflow: hidden;
  background: var(--bg-dark);
  font-family: var(--font-mono);
  color: var(--green);
}

/* --- Canvas --- */
#atlas-canvas {
  position: fixed;
  top: 0; left: 0;
  width: 100%; height: 100%;
  z-index: 1;
}

/* --- CRT Overlay --- */
.crt-overlay {
  position: fixed;
  top: 0; left: 0;
  width: 100%; height: 100%;
  pointer-events: none;
  z-index: 100;
  background:
    repeating-linear-gradient(
      0deg,
      rgba(0, 255, 0, 0.015) 0px,
      transparent 1px,
      transparent 3px
    ),
    radial-gradient(ellipse at center, transparent 60%, rgba(0, 0, 0, 0.4) 100%);
}

/* --- HUD (top-left) --- */
.hud {
  position: fixed;
  top: 16px; left: 16px;
  z-index: 50;
  pointer-events: none;
  font-family: var(--font-display);
  font-size: 22px;
  line-height: 1.4;
  color: var(--green);
  text-shadow: 0 0 8px var(--green-glow);
}

.hud-title {
  font-size: 28px;
  color: var(--amber);
  text-shadow: 0 0 12px rgba(255, 176, 0, 0.4);
  letter-spacing: 2px;
}

.hud-stats {
  font-size: 18px;
  color: var(--text-dim);
  margin-top: 4px;
}

.hud-stats span {
  color: var(--green);
}

/* --- Controls hint (bottom-left) --- */
.controls-hint {
  position: fixed;
  bottom: 16px; left: 16px;
  z-index: 50;
  pointer-events: none;
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
  line-height: 1.6;
  opacity: 0.7;
}

/* --- Info Panel (right side) --- */
.info-panel {
  position: fixed;
  top: 16px; right: 16px;
  bottom: 16px;
  width: 420px;
  z-index: 60;
  background: var(--bg-panel);
  border: 1px solid var(--border);
  border-radius: 4px;
  display: flex;
  flex-direction: column;
  transform: translateX(460px);
  transition: transform 0.3s ease-out;
  box-shadow:
    0 0 20px rgba(0, 255, 0, 0.05),
    inset 0 0 40px rgba(0, 0, 0, 0.3);
  overflow: hidden;
}

.info-panel.open {
  transform: translateX(0);
}

/* Panel titlebar */
.panel-titlebar {
  display: flex;
  align-items: center;
  padding: 8px 12px;
  background: rgba(0, 20, 0, 0.6);
  border-bottom: 1px solid var(--border);
  font-family: var(--font-mono);
  font-size: 12px;
  flex-shrink: 0;
}

.panel-dots {
  display: flex;
  gap: 6px;
  margin-right: 12px;
}

.panel-dot {
  width: 10px; height: 10px;
  border-radius: 50%;
  background: var(--green-dim);
  border: 1px solid var(--green);
  cursor: pointer;
}

.panel-dot:hover {
  background: var(--red);
  border-color: var(--red);
}

.panel-path {
  color: var(--text-dim);
  flex: 1;
}

.panel-path .prompt {
  color: var(--green);
}

/* Panel content */
.panel-content {
  flex: 1;
  overflow-y: auto;
  padding: 12px 16px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.7;
  scrollbar-width: thin;
  scrollbar-color: var(--green-dim) transparent;
}

.panel-content::-webkit-scrollbar {
  width: 6px;
}

.panel-content::-webkit-scrollbar-thumb {
